body.dark-mode .style-24,
body.dark-mode .style-24 a,
body.dark-mode .style-25,
body.dark-mode .style-25 a {
  color: #eeeeee;
}

/* Buttons */
body.dark-mode .button-8,
body.dark-mode .button-8 a,
body.dark-mode .button-8 a.active {
  color: #eeeeee;
  border-color: rgba(238, 238, 238, 0.7);
}

body.dark-mode .button-12,
body.dark-mode .button-12 a,
body.dark-mode .button-12 a.active {
  color: #eeeeee;
  background: #222222;
  border-color: rgba(238, 238, 238, 0.7);
}

/* Variable animation */
body.dark-mode .variable-animation,
body.dark-mode .variable-animation a {
  color: #eeeeee;
}

/* Answer/question bubbles */
body.dark-mode .answer-bubble {
  color: #eeeeee;
  background: #2a2a2e;
}

body.dark-mode .question-bubble {
  background: rgba(238, 238, 238, 0.15);
}

/* Header-2-bigger-bolder */
body.dark-mode .header-2-bigger-bolder a {
  color: rgba(238, 238, 238, 0.85);
}

/* Shop product */
body.dark-mode shop-product::part(price) {
  color: rgba(238, 238, 238, 0.75);
}

body.dark-mode shop-product::part(dropdown) {
  color: rgba(238, 238, 238, 0.85);
  border-color: rgba(238, 238, 238, 0.3);
  background-color: rgba(0, 0, 0, 0);
}

body.dark-mode shop-product::part(button) {
  background: rgba(238, 238, 238, 0.15);
  color: rgba(238, 238, 238, 0.75);
}

/* Toggle button styling */
#theme-switch {
  position: fixed;
  top: 1.2rem;
  right: 1.2rem;
  z-index: 9999;
  background: rgba(0, 0, 0, 0.08);
  border: 1px solid rgba(0, 0, 0, 0.15);
  border-radius: 2rem;
  padding: 0.4rem 0.8rem;
  font-size: 1.2rem;
  cursor: pointer;
  transition: background 0.2s, border-color 0.2s;
}

body.dark-mode #theme-switch {
  background: rgba(255, 255, 255, 0.1);
  border-color: rgba(255, 255, 255, 0.2);
}

@keyframes scrollAnimationFadeInOut-3 { 
    0% { opacity: 0; }
    30% { opacity: 1; }
    75% { opacity: 1; }
    100% { opacity: 0; }
}

